const Map<String, ChunkPatternListSource> authoredChunkPatternSourcesByLevel = <String, ChunkPatternListSource>{
  'field': ChunkPatternListSource(
    earlyPatterns: fieldEarlyPatterns,
    easyPatterns: fieldEasyPatterns,
    normalPatterns: fieldNormalPatterns,
    hardPatterns: fieldHardPatterns,
  ),
  'forest': ChunkPatternListSource(
    earlyPatterns: forestEarlyPatterns,
    easyPatterns: forestEasyPatterns,
    normalPatterns: forestNormalPatterns,
    hardPatterns: forestHardPatterns,
  ),
};

ChunkPatternListSource authoredChunkPatternSourceForLevel(
  String levelId,
) {
  final source = authoredChunkPatternSourcesByLevel[levelId];
  if (source != null) {
    return source;
  }
  throw StateError('No authored chunk pattern source for levelId="$levelId".');
}
